changeSet.sql:
DELETE FROM request_items
WHERE name IN ('Extra Towels', 'Extra Pillows', 'Extra Blanket', 'Toiletries')
AND category_id IN (
    SELECT id FROM request_categories WHERE name = 'Housekeeping'
);

UPDATE request_categories
SET name_am = 'ትራንስፖርት'
WHERE name = 'Transport' AND (name_am IS NULL OR name_am = '');
